#include <Arduino.h>
#include <freertos/task.h>
#include <freertos/semphr.h>
#include <freertos/queue.h>
#include <LiquidCrystal_I2C.h>

#define CAM_BIEN 13
#define LED 14

LiquidCrystal_I2C lcd(0x27, 16, 2);

typedef struct {
  int id;
  unsigned long timestamp;
} GoiTinCamBien;

QueueHandle_t hangdoi;
SemaphoreHandle_t CoCamBien;

void IRAM_ATTR ISR_CamBien() {
  BaseType_t xHigherPriorityTaskWoken = pdFALSE;
  xSemaphoreGiveFromISR(CoCamBien, &xHigherPriorityTaskWoken);
  portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
}

// ================= SENSOR TASK =================
void Sensor_Task(void *pvParameters) {

  GoiTinCamBien goitin;
  int dem = 0;

  vTaskDelay(pdMS_TO_TICKS(1000));  // chờ hệ thống ổn định

  while (1) {
    if (xSemaphoreTake(CoCamBien, portMAX_DELAY) == pdTRUE) {

      dem++;
      goitin.id = dem;
      goitin.timestamp = millis();

      xQueueSend(hangdoi, &goitin, portMAX_DELAY);

      vTaskDelay(pdMS_TO_TICKS(100));   // debounce nhẹ
    }
  }
}

// ================= LCD TASK =================
void LCD_Task(void *pvParameters) {

  GoiTinCamBien goitin_2;

  lcd.init();
  lcd.backlight();

  while (1) {

    if (xQueueReceive(hangdoi, &goitin_2, portMAX_DELAY) == pdTRUE) {

      lcd.clear();
      lcd.setCursor(0, 0);
      lcd.print("San Pham: ");
      lcd.print(goitin_2.id);

      lcd.setCursor(0, 1);
      lcd.print("Time: ");
      lcd.print(goitin_2.timestamp);

      digitalWrite(LED, HIGH);
      vTaskDelay(pdMS_TO_TICKS(1000));
      digitalWrite(LED, LOW);
    }
  }
}

void setup() {

  Serial.begin(115200);

  pinMode(CAM_BIEN, INPUT_PULLUP);
  pinMode(LED, OUTPUT);

  CoCamBien = xSemaphoreCreateBinary();
  hangdoi = xQueueCreate(10, sizeof(GoiTinCamBien));

  xTaskCreate(Sensor_Task, "Sensor_Task", 2048, NULL, 2, NULL);
  xTaskCreate(LCD_Task, "LCD_Task", 2048, NULL, 1, NULL);

  attachInterrupt(digitalPinToInterrupt(CAM_BIEN), ISR_CamBien, RISING);
}

void loop() {
  vTaskDelete(NULL);
}
```

