#include <Arduino.h>

// ==== CHÂN ====
#define FAN_PIN 2

// ==== QUEUE ====
QueueHandle_t tempQueue;

// ==== BIẾN ====
float temperature = 0;

// ================= TASK 1: ĐỌC NHIỆT ĐỘ =================
void TaskReadTemp(void *parameter) {
  while (1) {
    // giả lập nhiệt độ (20 -> 40 độ)
    float temp = random(200, 400) / 10.0;

    // gửi vào queue
    xQueueSend(tempQueue, &temp, portMAX_DELAY);

    vTaskDelay(pdMS_TO_TICKS(2000)); // 2 giây
  }
}

// ================= TASK 2: ĐIỀU KHIỂN =================
void TaskControlFan(void *parameter) {
  float temp;

  while (1) {
    if (xQueueReceive(tempQueue, &temp, portMAX_DELAY) == pdTRUE) {
      temperature = temp;

      if (temp > 30) {
        digitalWrite(FAN_PIN, HIGH);
      } else {
        digitalWrite(FAN_PIN, LOW);
      }
    }
  }
}

// ================= TASK 3: SERIAL =================
