#include <Arduino.h>

// ==== CHÂN ====
#define FAN_PIN 5

// ==== PID THAM SỐ ====
float Kp = 10.0;
float Ki = 0.5;
float Kd = 2.0;

// ==== BIẾN PID ====
float setpoint = 28.0;   // nhiệt độ mục tiêu
float input = 0;         // nhiệt độ hiện tại
float output = 0;        // PWM

float error = 0;
float lastError = 0;
float integral = 0;

// thời gian
unsigned long lastTime = 0;
float dt = 0;

// ================= SETUP =================
void setup() {
  Serial.begin(115200);
  pinMode(FAN_PIN, OUTPUT);
}

// ================= LOOP =================
void loop() {
  // ---- giả lập nhiệt độ (20 - 40 độ) ----
  input = random(200, 400) / 10.0;

  // ---- tính thời gian ----
  unsigned long now = millis();
  dt = (now - lastTime) / 1000.0; // giây
  lastTime = now;

  // ---- PID ----
  error = setpoint - input;

  integral += error * dt;
  float derivative = (error - lastError) / dt;

  output = Kp * error + Ki * integral + Kd * derivative;

  lastError = error;

  // ---- giới hạn PWM ----
  if (output > 255) output = 255;
  if (output < 0) output = 0;

  // ---- điều khiển quạt ----
  analogWrite(FAN_PIN, (int)output);

  // ---- debug ----
  Serial.print("Temp: ");
  Serial.print(input);
  Serial.print(" | Output: ");
  Serial.print(output);
  Serial.print(" | Error: ");
  Serial.println(error);

  delay(1000);
}
