#include <Arduino.h>

// ====== CHÂN ======
#define FAN_PIN 5

// ====== QUEUE ======
QueueHandle_t tempQueue;

// ====== BIẾN ======
float currentTemp = 0;

// ================= TASK 1: ĐỌC NHIỆT ĐỘ =================
void TaskReadTemp(void *parameter) {
  float temp;

  while (1) {
    // giả lập nhiệt độ (20 - 40°C)
    temp = random(200, 400) / 10.0;

    // gửi vào queue
    xQueueSend(tempQueue, &temp, portMAX_DELAY);

    vTaskDelay(pdMS_TO_TICKS(2000)); // 2 giây
  }
}

// ================= TASK 2: ĐIỀU KHIỂN QUẠT =================
void TaskControlFan(void *parameter) {
  float temp;

  while (1) {
    if (xQueueReceive(tempQueue, &temp, portMAX_DELAY) == pdTRUE) {
      currentTemp = temp;

      if (temp > 30) {
        digitalWrite(FAN_PIN, HIGH);
      } else {
        digitalWrite(FAN_PIN, LOW);
      }
    }
  }
}

// ================= TASK 3: HIỂN THỊ SERIAL =================
void TaskDisplay(void *parameter) {
  while (1) {
    Serial.print("Nhiet do: ");
    Serial.print(currentTemp);
    Serial.print(" *C | Fan: ");

    if (currentTemp > 30) {
      Serial.println("ON");
    } else {
      Serial.println("OFF");
    }

    vTaskDelay(pdMS_TO_TICKS(2000));
  }
}

// ================= SETUP =================
void setup() {
  Serial.begin(115200);
  pinMode(FAN_PIN, OUTPUT);

  // tạo queue (5 phần tử float)
  tempQueue = xQueueCreate(5, sizeof(float));

  // ===== TẠO TASK =====
  xTaskCreate(
    TaskReadTemp,
    "ReadTemp",
    2048,
    NULL,
    1,
    NULL
  );

  xTaskCreate(
    TaskControlFan,
    "ControlFan",
    2048,
    NULL,
    1,
    NULL
  );

  xTaskCreate(
    TaskDisplay,
    "Display",
    2048,
    NULL,
    1,
    NULL
  );
}

// ================= LOOP =================
void loop() {
  // không dùng loop vì đã có RTOS
}
