#include <Arduino.h>
#include <EEPROM.h>

// ===== CHÂN =====
#define LED_PIN 2
#define BUZZER_PIN 4

// ===== EEPROM =====
#define EEPROM_SIZE 4   // lưu float (4 byte)

// ===== BIẾN =====
float threshold = 30.0;   // ngưỡng mặc định
float temperature = 0;

// ===== THỜI GIAN NHÁY LED =====
unsigned long lastBlink = 0;
bool ledState = false;

// ================= ĐỌC EEPROM =================
void readThreshold() {
  EEPROM.get(0, threshold);

  // kiểm tra giá trị hợp lệ
  if (isnan(threshold) || threshold < 0 || threshold > 100) {
    threshold = 30.0;
  }
}

// ================= GHI EEPROM =================
void saveThreshold() {
  EEPROM.put(0, threshold);
  EEPROM.commit(); // ESP32 cần
}

// ================= XỬ LÝ SERIAL =================
void handleSerial() {
  if (Serial.available()) {
    String cmd = Serial.readStringUntil('\n');
    cmd.trim();

    if (cmd.startsWith("SET")) {
      float value = cmd.substring(4).toFloat();

      if (value > 0 && value < 100) {
        threshold = value;
        saveThreshold();

        Serial.print("Da luu nguong: ");
        Serial.println(threshold);
      } else {
        Serial.println("Gia tri khong hop le!");
      }
    }

    // bonus: in ngưỡng hiện tại
    if (cmd == "GET") {
      Serial.print("Nguong hien tai: ");
      Serial.print(threshold);
      Serial.println(" *C");
    }
  }
}

// ================= SETUP =================
void setup() {
  Serial.begin(115200);

  pinMode(LED_PIN, OUTPUT);
  pinMode(BUZZER_PIN, OUTPUT);

  EEPROM.begin(EEPROM_SIZE);
  readThreshold();

  Serial.print("Nguong hien tai: ");
  Serial.print(threshold);
  Serial.println(" *C");
}

