    digitalWrite(BUZZER_PIN, HIGH);

    // nháy LED mỗi 500ms
    if (millis() - lastBlink >= 500) {
      lastBlink = millis();
      ledState = !ledState;
      digitalWrite(LED_PIN, ledState);
