### [1] xinchao.ino  (đường dẫn: /xinchao/xinchao.ino)
```
#include <Arduino.h>

// ===== CHÂN =====
#define FAN_PIN 5
#define BUTTON_PIN 18

// ===== BIẾN =====
volatile bool mode = true;   // true = AUTO, false = MANUAL
volatile bool buttonPressed = false;

bool fanState = false;
float temperature = 0;

// debounce
unsigned long lastInterrupt = 0;

// ================= INTERRUPT =================
void IRAM_ATTR handleButton() {
  if (millis() - lastInterrupt > 200) { // debounce
    buttonPressed = true;
    lastInterrupt = millis();
  }
}

// ================= SETUP =================
void setup() {
  Serial.begin(115200);

  pinMode(FAN_PIN, OUTPUT);
  pinMode(BUTTON_PIN, INPUT_PULLUP);

  attachInterrupt(digitalPinToInterrupt(BUTTON_PIN), handleButton, FALLING);
}

// ================= LOOP =================
void loop() {
  // ---- giả lập nhiệt độ ----
  temperature = random(200, 400) / 10.0;

  // ---- xử lý nút ----
  if (buttonPressed) {
    buttonPressed = false;

    if (mode) {
      // đang AUTO -> chuyển MANUAL
      mode = false;
    } else {
      // đang MANUAL -> toggle quạt
      fanState = !fanState;
    }
  }

  // ---- AUTO MODE ----
  if (mode) {
    if (temperature > 30) {
      fanState = true;
    } else {
      fanState = false;
    }
  }

  // ---- điều khiển quạt ----
  digitalWrite(FAN_PIN, fanState ? HIGH : LOW);

  // ---- hiển thị ----
  Serial.print("Mode: ");
  Serial.print(mode ? "AUTO" : "MANUAL");
  Serial.print(" | Temp: ");
  Serial.print(temperature);
  Serial.print(" | Fan: ");
  Serial.println(fanState ? "ON" : "OFF");

  delay(1000);
}
