#include <Arduino.h>

#define PIR 14
#define LED 2
#define BUZZER 4
#define BUTTON 13

bool enableSystem = true;
int motionCount = 0;
unsigned long motionStart = 0;
bool isMotion = false;

// ================= TASK PIR =================
void taskPIR(void *pvParameters) {
  while (1) {
    int state = digitalRead(PIR);

    if (state == HIGH) {
      if (!isMotion) {
        isMotion = true;
        motionStart = millis();
        motionCount++;

        Serial.print("Motion detected: ");
        Serial.println(motionCount);
      }
    } else {
      isMotion = false;
      digitalWrite(LED, LOW);
      digitalWrite(BUZZER, LOW);
    }

    vTaskDelay(pdMS_TO_TICKS(100));
  }
}

// ================= TASK XỬ LÝ =================
void taskXuLy(void *pvParameters) {
  while (1) {
    if (enableSystem && isMotion) {
      unsigned long duration = (millis() - motionStart) / 1000;

      digitalWrite(LED, HIGH);

      if (duration > 5) {
        digitalWrite(BUZZER, HIGH);
      }

      if (duration > 10) {
        Serial.println("!!! CANH BAO: Co chuyen dong lau !!!");
      }
    }

    vTaskDelay(pdMS_TO_TICKS(200));
  }
}

// ================= TASK BUTTON =================
void taskButton(void *pvParameters) {
  bool last = HIGH;

  while (1) {
    bool now = digitalRead(BUTTON);

    if (last == HIGH && now == LOW) {
      enableSystem = !enableSystem;

      Serial.print("System: ");
      Serial.println(enableSystem ? "ON" : "OFF");

      vTaskDelay(pdMS_TO_TICKS(300));
    }

    last = now;
    vTaskDelay(pdMS_TO_TICKS(50));
  }
}

// ================= SETUP =================
void setup() {
  Serial.begin(115200);

  pinMode(PIR, INPUT);
  pinMode(LED, OUTPUT);
  pinMode(BUZZER, OUTPUT);
  pinMode(BUTTON, INPUT_PULLUP);

  xTaskCreate(taskPIR, "PIR", 2048, NULL, 1, NULL);
  xTaskCreate(taskXuLy, "XuLy", 2048, NULL, 1, NULL);
  xTaskCreate(taskButton, "Button", 2048, NULL, 1, NULL);
}

void loop() {}
